<?php
declare(strict_types=1);require __DIR__.'/../includes/bootstrap.php';require_role('lecturer');$page_title='Attendance - SMIS';$lecturer=db_one('SELECT * FROM lecturers WHERE user_id=:id',['id'=>current_user()['id']]);$assignment_id=(int)query('assignment');$assignments=db_all('SELECT lm.id,m.code,c.name class_name FROM lecturer_modules lm JOIN modules m ON m.id=lm.module_id JOIN classes c ON c.id=lm.class_id WHERE lm.lecturer_id=:id ORDER BY m.code',['id'=>$lecturer['id']]);$assignment=$assignment_id?db_one('SELECT lm.*,m.code,m.title,c.name class_name FROM lecturer_modules lm JOIN modules m ON m.id=lm.module_id JOIN classes c ON c.id=lm.class_id WHERE lm.id=:id AND lm.lecturer_id=:lecturer',['id'=>$assignment_id,'lecturer'=>$lecturer['id']]):null;$date=(string)query('date',date('Y-m-d'));
if(is_post()&&$assignment){enforce_csrf();$date=(string)post('attendance_date');foreach((array)post('status',[]) as $student=>$status){if(!in_array($status,['present','absent','late'],true))continue;db_execute('INSERT INTO attendance(student_id,module_id,class_id,lecturer_id,attendance_date,status,remarks) VALUES(:student,:module,:class,:lecturer,:date,:status,:remarks) ON DUPLICATE KEY UPDATE status=VALUES(status),remarks=VALUES(remarks),lecturer_id=VALUES(lecturer_id),class_id=VALUES(class_id)',['student'=>(int)$student,'module'=>$assignment['module_id'],'class'=>$assignment['class_id'],'lecturer'=>$lecturer['id'],'date'=>$date,'status'=>$status,'remarks'=>(string)post('remarks_'.$student)]);}audit_log('upload_attendance','modules',(string)$assignment['module_id']);respond_success('Attendance saved.','lecturer/attendance.php?assignment='.$assignment_id.'&date='.$date);}
$students=$assignment?db_all('SELECT s.id,s.student_number,u.name,a.status,a.remarks FROM students s JOIN users u ON u.id=s.user_id JOIN student_modules sm ON sm.student_id=s.id AND sm.module_id=:module AND sm.semester_id=:semester LEFT JOIN attendance a ON a.student_id=s.id AND a.module_id=:attendance_module AND a.attendance_date=:date WHERE s.class_id=:class ORDER BY u.name',['module'=>$assignment['module_id'],'semester'=>$assignment['semester_id'],'attendance_module'=>$assignment['module_id'],'date'=>$date,'class'=>$assignment['class_id']]):[];
include __DIR__.'/../includes/header.php';?><div class="page-header"><h1>Attendance</h1><p>Assigned students load automatically from the selected class and module.</p></div><div class="card"><div class="card-body"><form method="get" class="grid grid-col-3"><div class="form-group"><label>Assignment</label><select class="form-control" name="assignment"><?php foreach($assignments as $a):?><option value="<?=$a['id']?>" <?=$assignment_id===$a['id']?'selected':''?>><?=e($a['class_name'].' · '.$a['code'])?></option><?php endforeach?></select></div><div class="form-group"><label>Date</label><input class="form-control" type="date" name="date" value="<?=e($date)?>"></div><div class="form-group" style="align-self:end"><button class="btn btn-secondary">Load roster</button></div></form></div></div>
<?php if($assignment):?><form method="post"><?=csrf_field()?><input type="hidden" name="attendance_date" value="<?=e($date)?>"><div class="card"><div class="card-header"><?=e($assignment['class_name'].' · '.$assignment['code'].' '.$assignment['title'])?></div><div class="card-body"><table class="table"><thead><tr><th>Student</th><th>Status</th><th>Remarks</th></tr></thead><tbody><?php foreach($students as $s):?><tr><td><strong><?=e($s['name'])?></strong><br><small><?=e($s['student_number'])?></small></td><td><select class="form-control" name="status[<?=$s['id']?>]"><?php foreach(['present','absent','late'] as $status):?><option value="<?=$status?>" <?=($s['status']??'present')===$status?'selected':''?>><?=ucfirst($status)?></option><?php endforeach?></select></td><td><input class="form-control" name="remarks_<?=$s['id']?>" value="<?=e($s['remarks']??'')?>"></td></tr><?php endforeach?></tbody></table><button class="btn btn-primary" style="margin-top:18px">Upload attendance</button></div></div></form><?php endif?><?php include __DIR__.'/../includes/footer.php';?>
